// Combined EJS report template (all partials inlined — no filesystem access needed at runtime)
export const REPORT_TEMPLATE = String.raw`<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title><%= clientName %> - Analytics Report <%= reportMonth %></title>
  <link rel="preconnect" href="https://fonts.googleapis.com">
  <link rel="preconnect" href="https://fonts.gstatic.com" crossorigin>
  <link href="https://fonts.googleapis.com/css2?family=Fira+Mono:wght@400;500;700&display=swap" rel="stylesheet">
  <style>
    <%= tailwindCSS %>
  </style>
  <style>
    :root { --brand-color: <%= brandColor || '#654B73' %>; }
    body { font-family: 'Fira Mono', ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, monospace; }
    .brand-bg { background-color: var(--brand-color); }
    .brand-text { color: var(--brand-color); }
    .brand-border { border-color: var(--brand-color); }
    a { cursor: pointer; }
    @media print {
      .page-break { page-break-before: always; }
      .no-print { display: none !important; }
    }
  </style>
</head>
<body class="bg-brand-50 min-h-screen">

  <!-- HEADER -->
  <header class="brand-gradient-bg shadow-lg">
    <div class="max-w-7xl mx-auto px-6 py-12">
      <div class="flex items-center justify-between">
        <div>
          <p class="text-brand-200 text-sm font-medium uppercase tracking-wider mb-2">Analytics Report</p>
          <h1 class="text-3xl font-bold text-white"><%= clientName %></h1>
          <p class="mt-2 text-lg text-brand-100"><%= reportMonth %></p>
        </div>
        <div class="flex items-center gap-6">
          <% if (mainLogo) { %>
            <img src="<%= mainLogo %>" alt="Draft.dev" class="h-12 w-auto" />
          <% } %>
          <% if (clientLogo) { %>
            <img src="<%= clientLogo %>" alt="<%= clientName %> Logo" class="h-12 w-auto" />
          <% } %>
        </div>
      </div>
    </div>
  </header>

  <main class="max-w-7xl mx-auto px-6">

    <!-- KEY METRICS -->
    <% if (sections.includes('metrics') && metricsByCategory && Object.keys(metricsByCategory).length > 0) { %>
    <section class="py-10">
      <h2 class="brand-section-title mb-8">Key Metrics</h2>
      <%
        const allMetricsFlat = [];
        Object.keys(metricsByCategory).forEach(function(cat) {
          metricsByCategory[cat].forEach(function(m) { allMetricsFlat.push(m); });
        });
        const metricOrder = [
          'Pieces Delivered','Pieces Published','Avg. Time to Publish (days)',
          'Monthly Users','Backlinks','LLM Response Presence',
          'Citations of Website','Citation Consistency','Domain Rating',
          'SEO Keywords (Position 1-3)','SEO Keywords (Position 4-10)','Page Health Score'
        ];
        allMetricsFlat.sort(function(a,b){
          var ia = metricOrder.indexOf(a.metricName); var ib = metricOrder.indexOf(b.metricName);
          return (ia===-1?999:ia)-(ib===-1?999:ib);
        });
      %>
      <div style="display:grid;grid-template-columns:repeat(6,minmax(0,1fr));gap:0.5rem;">
        <% allMetricsFlat.forEach(function(metric) { %>
          <div class="brand-card p-3 hover:shadow-md transition-shadow duration-200" style="position:relative;overflow:visible;">
            <div style="display:flex;justify-content:space-between;align-items:flex-start;">
              <p class="text-xs font-medium text-brand-500 leading-tight"><%= metric.metricName %></p>
              <% if (metric.metricName === 'LLM Response Presence') { %>
                <div style="position:relative;display:inline-block;margin-left:4px;">
                  <svg onmouseenter="document.getElementById('llm-tooltip').style.display='block';" onmouseleave="document.getElementById('llm-tooltip').style.display='none';" style="width:14px;height:14px;cursor:help;color:#9CA3AF;" fill="currentColor" viewBox="0 0 20 20"><path fill-rule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-7-4a1 1 0 11-2 0 1 1 0 012 0zM9 9a1 1 0 000 2v3a1 1 0 001 1h1a1 1 0 100-2v-3a1 1 0 00-1-1H9z" clip-rule="evenodd"/></svg>
                  <div id="llm-tooltip" onmouseenter="this.style.display='block';" onmouseleave="this.style.display='none';" style="display:none;position:absolute;bottom:calc(100% + 8px);right:-10px;padding:8px 12px;background-color:#1F2937;color:white;font-size:12px;line-height:1.4;border-radius:6px;z-index:1000;box-shadow:0 4px 6px rgba(0,0,0,0.1);width:240px;">Measures how often a specific brand or content appears anywhere within an AI-generated answer.<div style="position:absolute;top:100%;right:20px;width:0;height:0;border-left:6px solid transparent;border-right:6px solid transparent;border-top:6px solid #1F2937;"></div></div>
                </div>
              <% } %>
              <% if (metric.metricName === 'Citations of Website') { %>
                <div style="position:relative;display:inline-block;margin-left:4px;">
                  <svg onmouseenter="document.getElementById('citations-tooltip').style.display='block';" onmouseleave="document.getElementById('citations-tooltip').style.display='none';" style="width:14px;height:14px;cursor:help;color:#9CA3AF;" fill="currentColor" viewBox="0 0 20 20"><path fill-rule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-7-4a1 1 0 11-2 0 1 1 0 012 0zM9 9a1 1 0 000 2v3a1 1 0 001 1h1a1 1 0 100-2v-3a1 1 0 00-1-1H9z" clip-rule="evenodd"/></svg>
                  <div id="citations-tooltip" onmouseenter="this.style.display='block';" onmouseleave="this.style.display='none';" style="display:none;position:absolute;bottom:calc(100% + 8px);right:-10px;padding:8px 12px;background-color:#1F2937;color:white;font-size:12px;line-height:1.4;border-radius:6px;z-index:1000;box-shadow:0 4px 6px rgba(0,0,0,0.1);width:240px;">Tracks instances where the LLM provides a direct reference or link to the original source, acknowledging its use.<div style="position:absolute;top:100%;right:20px;width:0;height:0;border-left:6px solid transparent;border-right:6px solid transparent;border-top:6px solid #1F2937;"></div></div>
                </div>
              <% } %>
              <% if (metric.metricName === 'Citation Consistency') { %>
                <div style="position:relative;display:inline-block;margin-left:4px;">
                  <svg onmouseenter="document.getElementById('consistency-tooltip').style.display='block';" onmouseleave="document.getElementById('consistency-tooltip').style.display='none';" style="width:14px;height:14px;cursor:help;color:#9CA3AF;" fill="currentColor" viewBox="0 0 20 20"><path fill-rule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-7-4a1 1 0 11-2 0 1 1 0 012 0zM9 9a1 1 0 000 2v3a1 1 0 001 1h1a1 1 0 100-2v-3a1 1 0 00-1-1H9z" clip-rule="evenodd"/></svg>
                  <div id="consistency-tooltip" onmouseenter="this.style.display='block';" onmouseleave="this.style.display='none';" style="display:none;position:absolute;bottom:calc(100% + 8px);right:-10px;padding:8px 12px;background-color:#1F2937;color:white;font-size:12px;line-height:1.4;border-radius:6px;z-index:1000;box-shadow:0 4px 6px rgba(0,0,0,0.1);width:280px;">The percentage of responses that have cited the source. Calculated by dividing responses that cited the source by total responses that cited any source.<div style="position:absolute;top:100%;right:20px;width:0;height:0;border-left:6px solid transparent;border-right:6px solid transparent;border-top:6px solid #1F2937;"></div></div>
                </div>
              <% } %>
            </div>
            <div class="mt-1 flex items-baseline flex-wrap">
              <p class="text-lg font-bold text-brand-900">
                <%= typeof metric.value === 'number' ? metric.value.toLocaleString() : metric.value %><%= metric.isPercentage ? '%' : '' %>
              </p>
              <% if (metric.change && metric.change.direction !== 'neutral') { %>
                <% var isGood = metric.lowerIsBetter ? metric.change.direction === 'down' : metric.change.direction === 'up'; %>
                <% var colorClass = isGood ? 'text-emerald-600' : 'text-rose-600'; %>
                <span class="ml-1 text-xs font-medium <%= colorClass %>">
                  <% if (metric.change.direction === 'up') { %>
                    <svg class="inline w-3 h-3" fill="currentColor" viewBox="0 0 20 20"><path fill-rule="evenodd" d="M5.293 9.707a1 1 0 010-1.414l4-4a1 1 0 011.414 0l4 4a1 1 0 01-1.414 1.414L11 7.414V15a1 1 0 11-2 0V7.414L6.707 9.707a1 1 0 01-1.414 0z" clip-rule="evenodd"/></svg>
                  <% } else { %>
                    <svg class="inline w-3 h-3" fill="currentColor" viewBox="0 0 20 20"><path fill-rule="evenodd" d="M14.707 10.293a1 1 0 010 1.414l-4 4a1 1 0 01-1.414 0l-4-4a1 1 0 111.414-1.414L9 12.586V5a1 1 0 012 0v7.586l2.293-2.293a1 1 0 011.414 0z" clip-rule="evenodd"/></svg>
                  <% } %>
                  <%= metric.change.formatted %>
                </span>
              <% } %>
            </div>
            <% if (metric.previousValue) { %>
              <p class="mt-1 text-xs text-brand-400">Prev: <%= typeof metric.previousValue === 'number' ? metric.previousValue.toLocaleString() : metric.previousValue %><%= metric.isPercentage ? '%' : '' %></p>
            <% } %>
          </div>
        <% }); %>
      </div>
    </section>
    <% } %>

    <!-- HIGHLIGHTS & LOWLIGHTS -->
    <% if (notes && notes.length > 0) { %>
    <%
      var highlights = (notes || []).filter(function(n){ return n.section === 'highlights'; });
      var lowlights  = (notes || []).filter(function(n){ return n.section === 'lowlights'; });

      function extractUrls(text) {
        if (!text) return [];
        var urlRegex = /(https?:\/\/[^\s<>"']+)/g;
        return text.match(urlRegex) || [];
      }
      function removeUrls(text) {
        if (!text) return '';
        return text.replace(/(https?:\/\/[^\s<>"']+)/g, '').replace(/\s+/g, ' ').trim();
      }
      function formatTextWithBullets(text) {
        if (!text) return '';
        var lines = text.split(/\n+/).map(function(l){ return l.trim(); }).filter(function(l){ return l.length > 0; });
        if (lines.length === 1) return text;
        return '<ul class="list-disc list-inside space-y-1">' + lines.map(function(l){ return '<li>' + l + '</li>'; }).join('') + '</ul>';
      }
      function getGridClasses(count) { return count === 1 ? 'col-span-full' : 'col-span-1'; }
      var imageCounter = 0;
      function getImageId() { return 'lightbox-img-' + (imageCounter++); }
    %>

    <!-- Lightbox -->
    <div id="lightbox-overlay" class="fixed inset-0 bg-black bg-opacity-80 z-50 hidden items-center justify-center p-4" onclick="closeLightbox(event)">
      <div class="relative max-w-5xl max-h-full">
        <button onclick="closeLightbox(event)" class="absolute -top-10 right-0 text-white text-3xl font-light hover:text-brand-200 transition-colors">&times;</button>
        <img id="lightbox-image" src="" alt="Screenshot" class="max-w-full max-h-[85vh] object-contain rounded-lg shadow-2xl" onclick="event.stopPropagation()"/>
      </div>
    </div>
    <script>
      function openLightbox(src){ var o=document.getElementById('lightbox-overlay'),i=document.getElementById('lightbox-image'); i.src=src; o.classList.remove('hidden'); o.classList.add('flex'); document.body.style.overflow='hidden'; }
      function closeLightbox(e){ if(e)e.stopPropagation(); var o=document.getElementById('lightbox-overlay'); o.classList.add('hidden'); o.classList.remove('flex'); document.body.style.overflow=''; }
      document.addEventListener('keydown',function(e){ if(e.key==='Escape')closeLightbox(); });
    </script>

    <% if (highlights.length > 0) { %>
    <section class="py-10">
      <h2 class="brand-section-title mb-8">Highlights</h2>
      <div class="grid grid-cols-1 md:grid-cols-2 gap-6">
        <% highlights.forEach(function(item) { %>
          <% var hasShot=(item.screenshotFile&&screenshots[item.screenshotFile])||item.embeddedImage; %>
          <% var imgSrc=item.embeddedImage||(item.screenshotFile&&screenshots[item.screenshotFile]); %>
          <% var urls=extractUrls(item.note); var cleanText=removeUrls(item.note); if(item.url&&!urls.includes(item.url))urls.push(item.url); %>
          <div class="brand-card overflow-hidden flex flex-col <%= getGridClasses(highlights.length) %>">
            <div class="p-5">
              <% if (item.title) { %><h3 class="text-base font-semibold text-brand-900 mb-2"><%= item.title %></h3><% } %>
              <% if (cleanText) { %><div class="text-sm text-brand-700 leading-relaxed"><%- formatTextWithBullets(cleanText) %></div><% } %>
              <% if (urls.length > 0) { %>
                <div class="mt-3">
                  <% if (urls.length === 1) { %>
                    <a href="<%= urls[0] %>" target="_blank" rel="noopener noreferrer" class="text-brand-600 hover:text-brand-800 underline text-sm break-all cursor-pointer"><%= urls[0] %></a>
                  <% } else { %>
                    <ul class="list-disc list-inside space-y-1"><% urls.forEach(function(u){ %><li><a href="<%= u %>" target="_blank" rel="noopener noreferrer" class="text-brand-600 hover:text-brand-800 underline text-sm break-all cursor-pointer"><%= u %></a></li><% }); %></ul>
                  <% } %>
                </div>
              <% } %>
            </div>
            <% if (hasShot) { %>
              <div class="bg-brand-50 border-t border-brand-100 flex-grow flex items-stretch justify-center overflow-hidden">
                <img src="<%= imgSrc %>" alt="<%= item.title || 'Screenshot' %>" class="w-full h-full cursor-pointer hover:opacity-95 transition-colors duration-200" style="object-fit:cover;" onclick="openLightbox('<%= imgSrc %>')"/>
              </div>
            <% } %>
            <% if (item.screenshots && item.screenshots.length > 1) { %>
              <% for(var si=1;si<item.screenshots.length;si++){ %>
                <div class="bg-brand-50 border-t border-brand-100 flex-grow flex items-stretch justify-center overflow-hidden">
                  <img src="<%= item.screenshots[si].data %>" alt="<%= item.title || 'Screenshot' %>" class="w-full h-full cursor-pointer hover:opacity-95 transition-colors duration-200" style="object-fit:cover;" onclick="openLightbox('<%= item.screenshots[si].data %>')"/>
                </div>
              <% } %>
            <% } %>
          </div>
        <% }); %>
      </div>
    </section>
    <% } %>

    <% if (lowlights.length > 0) { %>
    <section class="py-10">
      <h2 class="brand-section-title mb-8">Lowlights</h2>
      <div class="grid grid-cols-1 md:grid-cols-2 gap-6">
        <% lowlights.forEach(function(item) { %>
          <% var hasShot=(item.screenshotFile&&screenshots[item.screenshotFile])||item.embeddedImage; %>
          <% var imgSrc=item.embeddedImage||(item.screenshotFile&&screenshots[item.screenshotFile]); %>
          <% var urls=extractUrls(item.note); var cleanText=removeUrls(item.note); if(item.url&&!urls.includes(item.url))urls.push(item.url); %>
          <div class="brand-card overflow-hidden flex flex-col <%= getGridClasses(lowlights.length) %>">
            <div class="p-5">
              <% if (item.title) { %><h3 class="text-base font-semibold text-brand-900 mb-2"><%= item.title %></h3><% } %>
              <% if (cleanText) { %><div class="text-sm text-brand-700 leading-relaxed"><%- formatTextWithBullets(cleanText) %></div><% } %>
              <% if (urls.length > 0) { %>
                <div class="mt-3">
                  <% if (urls.length === 1) { %>
                    <a href="<%= urls[0] %>" target="_blank" rel="noopener noreferrer" class="text-brand-600 hover:text-brand-800 underline text-sm break-all cursor-pointer"><%= urls[0] %></a>
                  <% } else { %>
                    <ul class="list-disc list-inside space-y-1"><% urls.forEach(function(u){ %><li><a href="<%= u %>" target="_blank" rel="noopener noreferrer" class="text-brand-600 hover:text-brand-800 underline text-sm break-all cursor-pointer"><%= u %></a></li><% }); %></ul>
                  <% } %>
                </div>
              <% } %>
            </div>
            <% if (hasShot) { %>
              <div class="bg-brand-50 border-t border-brand-100 flex-grow flex items-stretch justify-center overflow-hidden">
                <img src="<%= imgSrc %>" alt="<%= item.title || 'Screenshot' %>" class="w-full h-full cursor-pointer hover:opacity-95 transition-colors duration-200" style="object-fit:cover;" onclick="openLightbox('<%= imgSrc %>')"/>
              </div>
            <% } %>
            <% if (item.screenshots && item.screenshots.length > 1) { %>
              <% for(var si=1;si<item.screenshots.length;si++){ %>
                <div class="bg-brand-50 border-t border-brand-100 flex-grow flex items-stretch justify-center overflow-hidden">
                  <img src="<%= item.screenshots[si].data %>" alt="<%= item.title || 'Screenshot' %>" class="w-full h-full cursor-pointer hover:opacity-95 transition-colors duration-200" style="object-fit:cover;" onclick="openLightbox('<%= item.screenshots[si].data %>')"/>
                </div>
              <% } %>
            <% } %>
          </div>
        <% }); %>
      </div>
    </section>
    <% } %>
    <% } %>

    <!-- CHARTS -->
    <% if (sections.includes('charts') && charts && charts.length > 0) { %>
    <%
      var largeCharts  = charts.filter(function(c){ return c.size === 'large'; });
      var smallCharts  = charts.filter(function(c){ return c.size === 'small'; });
      var mediumCharts = charts.filter(function(c){ return c.size === 'medium'; });
    %>
    <section class="py-10">
      <h2 class="brand-section-title mb-8">Charts</h2>
      <div class="grid grid-cols-1 lg:grid-cols-2 gap-6 mb-10">
        <% if (largeCharts.length > 0) { %>
          <div>
            <div class="brand-card p-6">
              <div style="height:400px;"><canvas id="<%= largeCharts[0].id %>"></canvas></div>
              <% if (largeCharts[0].description) { %><p class="mt-4 text-sm" style="color:#8B7BA8;font-style:italic;"><%= largeCharts[0].description %></p><% } %>
            </div>
          </div>
        <% } %>
        <% if (smallCharts.length > 0) { %>
          <div>
            <div class="grid grid-cols-2 gap-3">
              <% smallCharts.forEach(function(chart){ %>
                <div class="brand-card flex flex-col" style="padding:1.22rem;">
                  <div style="height:180px;"><canvas id="<%= chart.id %>"></canvas></div>
                  <% if (chart.description) { %><p class="mt-1 text-[10px] leading-tight" style="color:#8B7BA8;font-style:italic;"><%= chart.description %></p><% } %>
                </div>
              <% }); %>
            </div>
          </div>
        <% } %>
      </div>
      <% if (mediumCharts.length > 0) { %>
        <div class="grid grid-cols-1 lg:grid-cols-2 gap-6">
          <% mediumCharts.forEach(function(chart){ %>
            <div class="brand-card p-6">
              <div style="height:300px;"><canvas id="<%= chart.id %>"></canvas></div>
              <% if (chart.description) { %><p class="mt-4 text-sm" style="color:#8B7BA8;font-style:italic;"><%= chart.description %></p><% } %>
            </div>
          <% }); %>
        </div>
      <% } %>
    </section>
    <script src="https://cdn.jsdelivr.net/npm/chart.js@4.4.1/dist/chart.umd.min.js"></script>
    <script src="https://cdn.jsdelivr.net/npm/chartjs-plugin-datalabels@2.2.0/dist/chartjs-plugin-datalabels.min.js"></script>
    <script>
      document.addEventListener('DOMContentLoaded', function() {
        Chart.register(ChartDataLabels);
        <% charts.forEach(function(chart){ %>
          new Chart(document.getElementById('<%= chart.id %>'), <%- JSON.stringify(chart.config) %>);
        <% }); %>
        window.__chartsReady = true;
      });
    </script>
    <% } %>

    <!-- NOTES & QUESTIONS -->
    <% if (sections.includes('screenshots') && notes && notes.length > 0) { %>
    <%
      var filteredNotes = (notes || []).filter(function(n){ return n.section !== 'highlights' && n.section !== 'lowlights'; });
      function convertUrlsToLinks(text) {
        if (!text) return '';
        return text.replace(/(https?:\/\/[^\s<>"']+|www\.[^\s<>"']+)/g, function(url){
          var href = url.startsWith('www.') ? 'https://' + url : url;
          return '<a href="' + href + '" target="_blank" rel="noopener noreferrer" class="text-brand-600 hover:text-brand-700 underline">' + url + '</a>';
        });
      }
      function formatNotesText(text) {
        if (!text) return '';
        var lines = text.split(/\n+/).map(function(l){ return l.trim(); }).filter(function(l){ return l.length > 0; });
        var withLinks = lines.map(function(l){ return convertUrlsToLinks(l); });
        if (withLinks.length === 1) return withLinks[0];
        return '<ul class="list-disc list-inside space-y-1">' + withLinks.map(function(l){ return '<li>' + l + '</li>'; }).join('') + '</ul>';
      }
    %>
    <% if (filteredNotes && filteredNotes.length > 0) { %>
    <section class="py-10">
      <h2 class="brand-section-title mb-8">Notes &amp; Questions</h2>
      <div id="lightbox-overlay-notes" class="fixed inset-0 bg-black bg-opacity-80 z-50 hidden items-center justify-center" onclick="closeLightboxNotes(event)">
        <button onclick="closeLightboxNotes(event)" class="absolute -top-10 right-0 text-white text-3xl font-light hover:text-brand-200 transition-colors">&times;</button>
        <img id="lightbox-image-notes" src="" alt="Screenshot" class="max-w-full max-h-full object-contain" onclick="event.stopPropagation()"/>
      </div>
      <script>
        function openLightboxNotes(src){ var o=document.getElementById('lightbox-overlay-notes'),i=document.getElementById('lightbox-image-notes'); i.src=src; o.classList.remove('hidden'); o.classList.add('flex'); document.body.style.overflow='hidden'; }
        function closeLightboxNotes(e){ if(e)e.stopPropagation(); var o=document.getElementById('lightbox-overlay-notes'); o.classList.add('hidden'); o.classList.remove('flex'); document.body.style.overflow=''; }
      </script>
      <%
        var notesBySection = filteredNotes.reduce(function(acc,n){ var s=n.section||'general'; if(!acc[s])acc[s]=[]; acc[s].push(n); return acc; }, {});
      %>
      <% Object.keys(notesBySection).forEach(function(section){ %>
        <div class="mb-10">
          <div class="space-y-6">
            <% notesBySection[section].forEach(function(note){ %>
              <div class="brand-card overflow-hidden">
                <div class="p-6">
                  <% if (note.title) { %><h4 class="text-lg font-semibold text-brand-900"><%= note.title %></h4><% } %>
                  <% if (note.note) { %><div class="mt-3 text-brand-700 leading-relaxed"><%- formatNotesText(note.note) %></div><% } %>
                </div>
                <% if (note.screenshotFile && screenshots[note.screenshotFile]) { %>
                  <div class="bg-brand-50 border-t border-brand-100">
                    <img src="<%= screenshots[note.screenshotFile] %>" alt="<%= note.title %>" class="w-full h-auto cursor-pointer hover:opacity-95 transition-colors" style="object-fit:cover;" onclick="openLightboxNotes('<%= screenshots[note.screenshotFile] %>')"/>
                  </div>
                <% } %>
                <% if (note.screenshots && note.screenshots.length > 1) { %>
                  <% for(var ni=1;ni<note.screenshots.length;ni++){ %>
                    <div class="bg-brand-50 border-t border-brand-100">
                      <img src="<%= note.screenshots[ni].data %>" alt="<%= note.title %>" class="w-full h-auto cursor-pointer hover:opacity-95 transition-colors" style="object-fit:cover;" onclick="openLightboxNotes('<%= note.screenshots[ni].data %>')"/>
                    </div>
                  <% } %>
                <% } %>
              </div>
            <% }); %>
          </div>
        </div>
      <% }); %>
    </section>
    <% } %>
    <% } %>

  </main>

  <!-- FOOTER -->
  <footer class="brand-gradient-bg mt-16">
    <div class="max-w-7xl mx-auto px-6 py-8">
      <div class="flex items-center justify-between">
        <p class="text-sm text-brand-200"><%= clientName %> Analytics Report - <%= reportMonth %></p>
        <a href="#" onclick="window.print(); return false;" class="no-print text-xs text-brand-300 hover:text-white underline transition-colors">Save as PDF</a>
      </div>
    </div>
  </footer>

</body>
</html>`
